/**
 * 🕵️‍♂️ SHADOW LOGISTICS SIMULATION (READ-ONLY)
 * ---------------------------------------------------
 * Účel: Analyzovať "stratené" kilometre (jalové jazdy), ktoré systém momentálne nepočíta.
 * Bezpečnosť: Tento skript NIČ nezapisuje do tabuľky. Iba číta dáta a vypisuje log.
 */

function runShadowSimulation() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  // ⚙️ KONFIGURÁCIA: Uprav názvy listov podľa reality
  const SHEET_TASKS_NAME = "Archive"; // Kde sú uložené staré úlohy?
  const SHEET_SETTINGS_NAME = "Settings"; // Kde sú súradnice (ak existuje)?

  // ⚙️ NASTAVENIE EXTRAPOLÁCIE (Ak nemáme presné súradnice)
  // Ak skript nenájde súradnice, použije túto priemernú vzdialenosť pre jalovú jazdu (v metroch),
  // aby sme videli aspoň odhadovaný dopad.
  const AVG_GAP_DISTANCE_METERS = 150; 

  console.log("=== ŠTART TIEŇOVEJ SIMULÁCIE ===");

  // 1. Načítanie Úloh
  const sheetTasks = ss.getSheetByName(SHEET_TASKS_NAME);
  if (!sheetTasks) {
    console.error(`❌ Chyba: List '${SHEET_TASKS_NAME}' sa nenašiel.`);
    return;
  }

  const data = sheetTasks.getDataRange().getValues();
  const headers = data[0];

  // Nájdenie indexov stĺpcov (Dynamické vyhľadávanie)
  // Uprav názvy v úvodzovkách, ak sa v tabuľke volajú inak
  const colMap = {
    worker: headers.indexOf("completedBy"),      // Kto to robil
    start: headers.indexOf("startedAt"),         // Kedy začal
    end: headers.indexOf("completedAt"),         // Kedy skončil
    pickup: headers.indexOf("pickedFromSectorId"), // Odkiaľ bral (Sektor)
    dropoff: headers.indexOf("workplace"),       // Kam viezol (Pracovisko)
    officialKm: headers.indexOf("KM")            // KM, ktoré systém zarátal teraz (ak existuje)
  };

  // Kontrola stĺpcov
  if (colMap.worker === -1 || colMap.start === -1 || colMap.pickup === -1 || colMap.dropoff === -1) {
    console.error("❌ Chýbajú kľúčové stĺpce. Skontrolujte hlavičky: " + headers.join(", "));
    return;
  }

  // 2. Spracovanie dát a zoskupenie podľa pracovníkov
  let workersData = {};

  // Preskočíme hlavičku (i=1)
  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    const worker = row[colMap.worker];

    // Ignorujeme úlohy bez priradeného pracovníka alebo nedokončené
    if (!worker || row[colMap.end] === "") continue;

    if (!workersData[worker]) {
      workersData[worker] = [];
    }

    workersData[worker].push({
      rowId: i + 1,
      start: new Date(row[colMap.start]).getTime(),
      end: new Date(row[colMap.end]).getTime(),
      pickup: row[colMap.pickup],
      dropoff: row[colMap.dropoff],
      officialKm: parseFloat(row[colMap.officialKm]) || 0
    });
  }

  // 3. Simulácia Reťazenia (Pre každého skladníka)
  for (const workerName in workersData) {
    console.log(`\n👤 ANALÝZA PRACOVNÍKA: ${workerName}`);

    let tasks = workersData[workerName];

    // ZORADENIE PODĽA ČASU (Kritické pre reťazenie)
    tasks.sort((a, b) => a.start - b.start);

    let totalOfficialKm = 0;
    let totalShadowGapKm = 0; // Toto sú tie "stratené" km
    let gapCount = 0;

    // Iterujeme cez úlohy
    for (let j = 0; j < tasks.length; j++) {
      const currentTask = tasks[j];
      totalOfficialKm += currentTask.officialKm;

      // Ak to nie je prvá úloha dňa, hľadáme medzeru
      if (j > 0) {
        const previousTask = tasks[j - 1];

        // Logika: Skončil na 'Dropoff' minulej úlohy -> Musel ísť na 'Pickup' aktuálnej úlohy
        const startPoint = previousTask.dropoff;
        const targetPoint = currentTask.pickup;

        // Tu by sme v ideálnom svete vypočítali: getDistance(startPoint, targetPoint)
        // Keďže nemáme teraz súradnice v pamäti, použijeme odhad alebo 0 ak sú body rovnaké

        let gapDist = 0;
        if (startPoint !== targetPoint) {
           // Ak sa miesta líšia, musel sa presunúť.
           // Tu simulujeme výpočet. V reále by si tu volal funkciu s X,Y.
           gapDist = AVG_GAP_DISTANCE_METERS / 1000; // Prevod na KM
        }

        totalShadowGapKm += gapDist;
        gapCount++;

        // Voliteľný detailný log pre prvých pár úloh
        if (j < 4) {
           console.log(`   [Medzera] ${previousTask.dropoff} -> ${currentTask.pickup} (+${gapDist.toFixed(3)} km)`);
        }
      }
    }

    // 4. Výsledný Report
    const totalSimulatedKm = totalOfficialKm + totalShadowGapKm;
    const increasePercent = totalOfficialKm > 0 ? ((totalSimulatedKm - totalOfficialKm) / totalOfficialKm) * 100 : 0;

    console.log(`   📊 VÝSLEDOK:`);
    console.log(`   - Oficiálne KM (Systém): ${totalOfficialKm.toFixed(2)} km`);
    console.log(`   - Jalové jazdy (Simulácia): ${totalShadowGapKm.toFixed(2)} km (${gapCount} presunov)`);
    console.log(`   - SPOLU REALITA: ${totalSimulatedKm.toFixed(2)} km`);
    console.log(`   - Rozdiel: +${increasePercent.toFixed(1)} %`);
  }

  console.log("\n=== KONIEC SIMULÁCIE ===");
}

